Here is the cycle-safe deep clone implementation:

```typescript
export default function deepClone<T>(value: T, seen = new WeakMap<object, unknown>()): T {
  // Handle primitives and functions
  if (value === null || typeof value !== 'object') {
    return value;
  }

  // Handle cycles
  if (seen.has(value as object)) {
    return seen.get(value as object) as T;
  }

  // Date
  if (value instanceof Date) {
    const cloned = new Date(value.getTime());
    seen.set(value, cloned);
    return cloned as unknown as T;
  }

  // RegExp
  if (value instanceof RegExp) {
    const cloned = new RegExp(value.source, value.flags);
    cloned.lastIndex = 0;
    seen.set(value, cloned);
    return cloned as unknown as T;
  }

  // Map
  if (value instanceof Map) {
    const cloned = new Map();
    seen.set(value, cloned);
    for (const [k, v] of value) {
      cloned.set(deepClone(k, seen), deepClone(v, seen));
    }
    return cloned as unknown as T;
  }

  // Set
  if (value instanceof Set) {
    const cloned = new Set();
    seen.set(value, cloned);
    for (const v of value) {
      cloned.add(deepClone(v, seen));
    }
    return cloned as unknown as T;
  }

  // ArrayBuffer
  if (value instanceof ArrayBuffer) {
    const cloned = value.slice(0);
    seen.set(value, cloned);
    return cloned as unknown as T;
  }

  // Array
  if (Array.isArray(value)) {
    const cloned: unknown[] = [];
    seen.set(value, cloned);
    for (let i = 0; i < value.length; i++) {
      cloned[i] = deepClone(value[i], seen);
    }
    return cloned as unknown as T;
  }

  // Plain objects and class instances
  const proto = Object.getPrototypeOf(value);
  const cloned = Object.create(proto);
  seen.set(value as object, cloned);

  for (const key of Object.getOwnPropertyNames(value)) {
    cloned[key] = deepClone((value as Record<string, unknown>)[key], seen);
  }

  for (const sym of Object.getOwnPropertySymbols(value)) {
    cloned[sym] = deepClone((value as Record<symbol, unknown>)[sym], seen);
  }

  return cloned;
}
